app.get('/login', (req, res) => {
  const state = randomString(16);
  const nonce = randomString(16);

  req.session.oidcState = state;
  req.session.oidcNonce = nonce;

  const params = {
    response_type: 'code',
    client_id: CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope: SCOPE,
    state,
    nonce,
  };

  const authorizationUrl = `${OIDC_AUTHORIZATION_ENDPOINT}?${qs.stringify(params)}`;
  res.redirect(authorizationUrl);
});

app.get('/callback', async (req, res) => {
  const { code, state, error, error_description } = req.query;

  if (error) {
    return res.status(400).send(`OIDC error: ${error}${error_description ? ` - ${error_description}` : ''}`);
  }

  if (!code || !state) {
    return res.status(400).send('Missing authorization code or state');
  }

  if (!req.session.oidcState || state !== req.session.oidcState) {
    return res.status(400).send('Invalid state');
  }

  try {
    const tokenResponse = await axios.post(
      OIDC_TOKEN_ENDPOINT,
      qs.stringify({
        grant_type: 'authorization_code',
        code,
        redirect_uri: REDIRECT_URI,
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET,
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
      }
    );

    const tokens = tokenResponse.data;

    if (!tokens.id_token) {
      return res.status(400).send('No id_token returned from token endpoint');
    }

    const decoded = jwt.decode(tokens.id_token);

    if (!decoded || typeof decoded !== 'object') {
      return res.status(400).send('Unable to decode id_token');
    }

    req.session.user = {
      sub: decoded.sub || null,
      email: decoded.email || null,
      name: decoded.name || null,
    };

    req.session.tokens = {
      access_token: tokens.access_token || null,
      refresh_token: tokens.refresh_token || null,
      id_token: tokens.id_token,
      token_type: tokens.token_type || null,
      expires_in: tokens.expires_in || null,
      scope: tokens.scope || null,
    };

    delete req.session.oidcState;
    delete req.session.oidcNonce;

    res.redirect('/');
  } catch (err) {
    const status = err.response?.status || 500;
    const data = err.response?.data || err.message;
    res.status(status).send(`Token exchange failed: ${typeof data === 'string' ? data : JSON.stringify(data)}`);
  }
});

